//==========================================
// Implementacion de HashMap
//==========================================

typedef struct entry {
  void *key, *val;
  struct entry *next;
} Entry;

struct map {
  int capacity;
  Entry **entries;
  HashFun hash;
  EqualsFun equals;
  int hasNext;
};

struct map_iterator {
  Map *map;
  int idx;
  Entry *entry;
};

Map *makeHashMap(int capacity, HashFun hash, EqualsFun equals) {
  Map *map= malloc(sizeof(Map));
  map->capacity= capacity;
  map->hash= hash;
  map->equals= equals;
  map->entries= malloc(capacity*sizeof(Entry*));
  for (int i= 0; i<capacity; i++) {
    map->entries[i]= NULL;
  }
  return map;
}

void destroyHashMap(Map *map) {
  for (int i= 0; i<map->capacity; i++) {
    Entry *entry= map->entries[i];
    while (entry!=NULL) {
      Entry *next= entry->next;
      free(entry);
      entry= next;
    }
  }
  free(map->entries);
  free(map);
}

static Entry **queryEntry(Map *map, int idx, void *key) {
  Entry **pentry= & map->entries[idx];
  Entry *entry= *pentry;
  while (entry!=NULL) {
    if ((*map->equals)(key, entry->key))
      return pentry;
    pentry= &entry->next;
    entry= entry->next;
  }
  return NULL;
}

void *query(Map *map, void *key) {
  int idx= (*map->hash)(key) % map->capacity;
  Entry **pentry= queryEntry(map, idx, key);
  if (pentry==NULL)
    return NULL;
  else
    return (*pentry)->val;
}

int define(Map *map, void *key, void *val) {
  int idx= (*map->hash)(key) % map->capacity;
  Entry **pentry= queryEntry(map, idx, key);
  if (pentry!=NULL) {
    (*pentry)->val= val;
    return 1;
  }
  else {
    Entry *entry= malloc(sizeof(Entry));
    entry->key= key;
    entry->val= val;
    entry->next= map->entries[idx];
    map->entries[idx]= entry;
    return 0;
  }
}

void *del(Map *map, void *key) {
  int idx= (*map->hash)(key) % map->capacity;
  Entry **pentry= queryEntry(map, idx, key);
  if (pentry==NULL) {
    return NULL;
  }
  else {
    Entry *entry= *pentry;
    void *val= entry->val;
    *pentry= entry->next;
    free(entry);
    return val;
  }
} 

int contains(Map *map, void *key) {
  int idx= (*map->hash)(key) % map->capacity;
  Entry **pentry= queryEntry(map, idx, key);
  return pentry!=NULL;
}

static void advance(MapIterator *iter) {
  Entry *entry= iter->entry;
  while (entry==NULL) {
    if (iter->idx >= iter->map->capacity) {
      break;
    }
    entry= iter->map->entries[iter->idx++];
  }
  iter->entry= entry;
}

MapIterator *getMapIterator(Map *map) {
  MapIterator *iter= malloc(sizeof(MapIterator));
  iter->idx= 1;
  iter->entry= map->entries[0];
  iter->map= map;
  advance(iter);
  return iter;
}

void destroyMapIterator(MapIterator *iter) {
  free(iter);
}

int mapNext(MapIterator *iter, void **pkey, void **pval) {
  Entry *entry= iter->entry;
  if (entry==NULL) {
    return 0;
  }
  else {
    *pkey= entry->key;
    *pval= entry->val;
    iter->entry= entry->next;
    advance(iter);
    return 1;
  }
}

int mapHasNext(MapIterator *iter) {
  return iter->entry!=NULL;
}

void resetMapIterator(MapIterator *iter) {
  iter->entry= iter->map->entries[0];
  iter->idx= 1;
  advance(iter);
}

//==========================================
// Funciones de hashing
//==========================================

unsigned hash_ptr(void *ptr) {
    unsigned h = (uintptr_t) ptr / 16;
    return h;
}


int pointer_equals(void *ptr1, void* ptr2) {
    return ptr1 == ptr2;
}

unsigned hash_string(void *str) {
    unsigned total = 2;
    for (char *reader = str; *reader; ++reader) {
        total += *reader;
        total *= 5;
    }
    return total;
}

int equals_strings(void *ptrX, void *ptrY) {
    return strcmp((char *)ptrX, (char *)ptrY) == 0;
}

//==========================================
// Implementacion de Queue
//==========================================

typedef struct node {
    void *val;
    struct node *next;
} QueueNode;

struct queue {
    QueueNode *first, **plast;
    int len;
};

Queue *makeQueue() {
    Queue *q = malloc(sizeof(Queue));
    q->first = NULL;
    q->plast = &q->first;
    q->len = 0;
    return q;
}

void put(Queue *q, void *ptr) {
    QueueNode *node = malloc(sizeof(QueueNode));
    node->val = ptr;
    node->next = NULL;
    *q->plast = node;
    q->plast = &node->next;
    q->len++;
}

void *get(Queue *q) {
    if (q->first == NULL) {
        return NULL;
    }
    void *val = q->first->val;
    QueueNode *next = q->first->next;
    free(q->first);
    q->first = next;
    if (next == NULL) {
        q->plast = &q->first;
    }
    q->len--;
    return val;
}

void *peek(Queue *q) {
    if (q->first == NULL) {
        return NULL;
    } else {
        return q->first->val;
    }
}

int emptyQueue(Queue *q) {
    return q->first == NULL;
}

int queueLength(Queue *q) {
    return q->len;
}

void destroyQueue(Queue *q) {
    QueueNode *node = q->first;
    while (node != NULL) {
        QueueNode *next = node->next;
        free(node);
        node = next;
    }
    free(q);
}

//==========================================
// Implementacion de sort generico
//==========================================

void sort(void *ptr, int left, int right,
          Comparator compare, Swapper swap) {
  int i, last;

  if (left>=right)
    return;

  (*swap)(ptr, left, (left+right)/2);
  last= left;

  /*
    +--+-----------+--------+--------------+
    |  |///////////|\\\\\\\\|              |
    +--+-----------+--------+--------------+
    left        last         i         right
  */

  for (i= left+1; i<=right; ++i)
    if ((*compare)(ptr, i, left)<0)
      (*swap)(ptr, ++last, i);
  (*swap)(ptr, left, last);

  sort(ptr, left, last-1, compare, swap);
  sort(ptr, last+1, right, compare, swap);
}

//==========================================
// Implementacion de Cola de Prioridad general
//==========================================

// Adapted from https://www.geeksforgeeks.org/priority-queue-using-binary-heap/

struct priqueue {
  PriComparator compare;
  int maxsize, size;
  void **ar;
};

PriQueue *makeFullPriQueue(int iniSize, PriComparator compare) {
  PriQueue *q= malloc(sizeof(PriQueue));
  q->compare= compare;
  q->maxsize= iniSize;
  q->size= -1;
  q->ar= malloc(iniSize*sizeof(void*));
  return q;
}

void destroyPriQueue(PriQueue *q) {
  free(q->ar);
  free(q);
}

void *fullPriPeek(PriQueue *q) {
  return q->size==-1 ? NULL : q->ar[0];
}

int emptyPriQueue(PriQueue *q) {
  return q->size==-1;
}

int priLength(PriQueue *q) {
  return q->size+1;
}

static void shiftUp(PriQueue *q, int i) {
  void **ar= q->ar;
  PriComparator compare= q->compare;
  int parent_i= (i-1)/2;
  while (i>0 && compare(ar[parent_i],ar[i])<0) {
    void *tmp= ar[parent_i]; // swap ar[parent_i] and ar[i]
    ar[parent_i]= ar[i];
    ar[i]= tmp;
    i= parent_i;
    parent_i= (i-1)/2;
  }
}

static void shiftDown(PriQueue *q, int i) {
  void **ar= q->ar;
  int size= q->size;
  PriComparator compare= q->compare;

  for (;;) {
    int maxIndex= i;
    int left= 2*i+1;
    if (left<=size && compare(ar[left], ar[maxIndex])>0)
      maxIndex= left;

    int right= 2*i+2;
    if (right<=size && compare(ar[right],ar[maxIndex])>0)
      maxIndex= right;
    if (i==maxIndex)
      break;
    void *tmp= ar[i]; // swap ar[i] and ar[maxIndex]
    ar[i]= ar[maxIndex];
    ar[maxIndex]= tmp;
    i= maxIndex;
  }
}

void fullPriPut(PriQueue *q, void *elem) {
  if (q->size+1==q->maxsize) {
    void **newAr= malloc(q->maxsize*2*sizeof(void*));
    for (int i= 0; i<=q->size; i++)
      newAr[i]= q->ar[i];
    free(q->ar);
    q->ar= newAr;
    q->maxsize= q->maxsize*2;
  }
  q->size++;
  q->ar[q->size] = elem;
  shiftUp(q, q->size);
}

void *fullPriGet(PriQueue *q) {
  void *result= q->ar[0];
  q->ar[0]= q->ar[q->size];
  q->size--;
  shiftDown(q, 0);
  return result;
}

//==========================================
// Implementacion de Cola de Prioridad simplificada
//==========================================

typedef struct {
  double pri;
  void *elem;
} PriObj;

static int priCmpFun(void *elemA, void *elemB) {
  PriObj *a= elemA;
  PriObj *b= elemB;
  double cmp= b->pri-a->pri;
  return cmp>0 ? 1 : (cmp<0 ? -1 : 0);
}

PriQueue *makePriQueue(void) {
  return makeFullPriQueue(16, priCmpFun);
}

void *priPeek(PriQueue *q) {
  PriObj *priobj= fullPriPeek(q);
  return priobj==NULL ? NULL : priobj->elem;
}

double priBest(PriQueue *q) {
  PriObj *priobj= fullPriPeek(q);
  return priobj==NULL ? 0 : priobj->pri;
}

void *priGet(PriQueue *q) {
  PriObj *priobj= fullPriGet(q);
  if (priobj==NULL)
    return NULL;
  else {
    void *res= priobj->elem;
    free(priobj);
    return res;
  }
}

void priPut(PriQueue *q, void *elem, double pri) {
  PriObj *priobj= malloc(sizeof(PriObj));
  priobj->pri= pri;
  priobj->elem= elem;
  fullPriPut(q, priobj);
}

#include "nthread-impl.h"

#include <errno.h>
#include <stdint.h>
#include <signal.h>
#include <stdarg.h>
#include <string.h>

static void nth_RTimerHandler(int sig, siginfo_t *si, void *uc);
static void nth_wakeThreads(void);

static NthTimeQueue *nth_timeQueue;
static long long nth_iniTime= 0;
static long long nth_last_time= 0;
static long long nth_last_coreId= 0;
static timer_t nth_realTimer;

/*************************************************************
 * Prolog and epilog
 *************************************************************/

void nth_timeInit(void) {

  struct timespec ts;
  int rc= clock_gettime(CLOCK_REALTIME, &ts);
  if (rc!=0) {
    if (rc==-1)
      perror("clock_gettime");
    nFatalError("clock_gettime", "Failed to get time, cannot continue\n");
  }
  nth_iniTime= (long long)ts.tv_sec*1000000000LL+ts.tv_nsec;

  nth_timeQueue= nth_makeTimeQueue();

  struct sigaction sigact;
  sigact.sa_flags= SA_SIGINFO;
  sigact.sa_sigaction= nth_RTimerHandler;
  sigact.sa_mask= nth_sigsetCritical;

  if (sigaction(SIGALRM, &sigact, NULL)!=0) {
    perror("sigaction");
    nFatalError("nth_timeInit", "Failed to register signal, cannot continue\n");
  }

  struct sigevent sigev;
  sigev.sigev_notify= SIGEV_SIGNAL;
  sigev.sigev_signo= SIGALRM;
  sigev.sigev_value.sival_ptr= &nth_realTimer;
  if ( timer_create(CLOCK_REALTIME,
                    &sigev, &nth_realTimer)!=0 ) {
    perror("timer_create");
    nFatalError("nth_timeInit", "Failed to create timer, cannot continue\n");
  }
}

void nth_timeEnd(void) {
  if (!nth_emptyTimeQueue(nth_timeQueue))
    nFPrintf(stderr, "*** There are pending threads in the time queue\n");
}

/*************************************************************
 * Timeout management
 *************************************************************/

long long nGetTimeNanos(void) {
  START_CRITICAL
  struct timespec ts;
  int rc= clock_gettime(CLOCK_REALTIME, &ts);
  if (rc!=0) {
    if (rc==-1)
      perror("clock_gettime");
    nFatalError("clock_gettime", "Failed to get time, cannot continue\n");
  }
  long long curr_time= (long long)ts.tv_sec*1000000000LL+ts.tv_nsec-nth_iniTime;
  if (curr_time<nth_last_time)
#if 0
    nFatalError("nGetTimeNanos", "Previous time newer than current time "
                "(delta=%lld cores= %d %d)\n", curr_time-nth_last_time,
                 nth_last_coreId, nth_coreId());
#else
     curr_time= nth_last_time+1;
#endif
  nth_last_time= curr_time;
  nth_last_coreId= nth_coreId();
  END_CRITICAL
  return curr_time;
}

int nGetTime(void) {
  return nGetTimeNanos()/1000000LL;
}

static void nth_setRealTimerAlarm(long long nanos) {
  struct itimerspec spec;
  spec.it_value.tv_sec= nanos/1000000000;
  spec.it_value.tv_nsec= nanos%1000000000;
  spec.it_interval.tv_sec= 0;
  spec.it_interval.tv_nsec= 0;
  int rc= timer_settime(nth_realTimer, 0, &spec, NULL);
  if (rc!=0) {
    if (rc==-1)
      perror("timer_settime");
    nFatalError("timer_settime", "Failed to set time alarm, cannot continue\n");
  }
  nth_alarmArmed= nanos==0 ? 0 : 1;
}

void nth_programTimer(long long nanos, void (*wakeUpFun)(nThread th)) {
  CHECK_CRITICAL("nth_programTimer")
  nThread thisTh= nSelf();
  if (nanos<=0) {
#   ifdef TRACESCHED
      printk( "SCHED %d:timer not programmed %s %s\n", nth_coreId(),
              thisTh->name, nth_stateNames[thisTh->status]);
#   endif
    setReady(thisTh);
  }
  else {
    long long currTime= nGetTimeNanos();
    long long wakeTime= currTime+nanos;
    if ( nth_emptyTimeQueue(nth_timeQueue) ||
         wakeTime-nth_nextTime(nth_timeQueue)<0 ) {
#     ifdef TRACESCHED
        printk( "SCHED %d:timer set %s %s after %lld us at %lld us\n",
                nth_coreId(),
                thisTh->name, nth_stateNames[thisTh->status],
                (wakeTime-currTime)/1000, currTime/1000 );
#     endif
      nth_setRealTimerAlarm(wakeTime-currTime);
    }
#   ifdef TRACESCHED
    else {
      printk( "SCHED %d:timer programmed %s %s after %lld us at %lld us\n",
              nth_coreId(),
              thisTh->name, nth_stateNames[thisTh->status],
              (wakeTime-currTime)/1000, currTime/1000 );
    }
#   endif
    thisTh->wakeUpFun= wakeUpFun;
    nth_putTimed(nth_timeQueue, thisTh, wakeTime);
  }
}

void nth_cancelThread(nThread th) {
  CHECK_CRITICAL("nth_cancelTask")
# ifdef TRACESCHED
    long long currTime= nGetTimeNanos();
    nThread thisTh= nth_selfCritical();
    printk( "SCHED %d:%s cancels %s %s at %lld us\n", nth_coreId(),
            thisTh->name, th->name, nth_stateNames[th->status],
            currTime/1000 );
# endif
  nth_delTimed(nth_timeQueue, th);
  nth_wakeThreads();
}

static void nth_wakeThreads(void) {
  long long currTime= nGetTimeNanos();
  // Wake up all threads with wake time <= currTime
  while ( !nth_emptyTimeQueue(nth_timeQueue) &&
          nth_nextTime(nth_timeQueue)-currTime<=0 ) {
    nThread th= nth_getTimed(nth_timeQueue);
    if (th->wakeTime-currTime>0)
      nFatalError("nth_wakeThreads", "Inconsistent wake time");
#   ifdef TRACESCHED
      nThread thisTh= nth_selfCritical();
      printk( "SCHED %d: %s wakes up %s %s at %lld us ", nth_coreId(),
              thisTh->name, th->name, nth_stateNames[th->status],
              currTime/1000 );
#   endif
    if (th->wakeUpFun!=NULL)
      (*th->wakeUpFun)(th);
    setReady(th);
  }

  if (nth_emptyTimeQueue(nth_timeQueue)) {
    nth_setRealTimerAlarm(0);
#   ifdef TRACESCHED
      printk("timer unarmed\n");
#   endif
  }
  else {
#   ifdef TRACESCHED
      printk( "timer armed after %lld us\n",
              (nth_nextTime(nth_timeQueue)-currTime)/1000 );
#   endif
    nth_setRealTimerAlarm(nth_nextTime(nth_timeQueue)-currTime);
  }
}

static void nth_RTimerHandler(int sig, siginfo_t *si, void *uc) {
  // If this core is waiting in nth_rrSchedule, a return to nth_rrSchedule
  // is mandatory because calling recursively nth_rrSchedule is unsafe

  START_HANDLER

#   ifdef TRACESCHED
      printk( "SCHED %d:SIGVTALRM %s\n", nth_coreId(),
              nth_coreIsIdle[nth_coreId()] ? "idle" : "busy" );
#   endif

  nth_wakeThreads();
  // Buggy: if (! nth_coreIsIdle[nth_coreId()] && th!=NULL)
  if (! nth_coreIsIdle[nth_coreId()])
    schedule();

  END_HANDLER
}

/*************************************************************
 * nSleepNanos
 *************************************************************/

int nSleepNanos(long long nanos) {
  START_CRITICAL

  suspend(WAIT_SLEEP);
  nth_programTimer(nanos, NULL);
  schedule();

  END_CRITICAL
  return 0;
}

int nSleepMillis(long long millis) {
  nSleepNanos(millis*1000000LL);
  return 0;
}

int nSleepMicros(long long micros) {
  nSleepNanos(micros*1000LL);
  return 0;
}

int nSleepSeconds(unsigned int seconds) {
  nSleepNanos(seconds*1000000000LL);
  return 0;
}

#define _XOPEN_SOURCE 500

#include "nthread-impl.h"

static NthQueue *nth_fcfsReadyQueue;

static void nth_fcfsSetReady(nThread th) {
  CHECK_CRITICAL("nth_fcfsSetReady")

  if (th->status==READY || th->status==RUN)
    nFatalError("nth_fcfsReady", "The thread was already in READY status\n");

  th->status= READY;
  if (nth_allocCoreId(th)<0)
    nth_putBack(nth_fcfsReadyQueue, th);
  else if (nth_allocCoreId(th)!=nth_coreId()) {
#if 0
    DBG(
      printf("wake core %d up from %d\n", nth_allocCoreId(th), nth_coreId());
    );
#endif
    nth_coreWakeUp(nth_allocCoreId(th));
  }
}

static void nth_fcfsSuspend(State waitState) {
  CHECK_CRITICAL("nth_fcfsSuspend")

  nThread th= nSelf();
  // if (th->status==READY)
  //   nth_delQueue(nth_fcfsReadyQueue, th);
  // else
  assert(th->status==RUN);

  th->status= waitState;
}

static void nth_fcfsSchedule(void) {
  CHECK_CRITICAL("nth_fcfsSchedule")

  // int prevCoreId= coreId();
  nThread thisTh= nSelf();

  for (;;) {
    if (thisTh!=NULL && (thisTh->status==READY || thisTh->status==RUN)) {
      if (nth_allocCoreId(thisTh)<0 && thisTh->status==READY)
        nth_delQueue(nth_fcfsReadyQueue, thisTh);
      break;              // Continue running same allocated thread
    }

    nThread nextTh= nth_getFront(nth_fcfsReadyQueue);
    if (nextTh!=NULL) {
      // The context change: give this core to nextTh
      // it will take a while to return from here
      // Meanwhile thread nextTh and others are being executed
      DBG (
        if (thisTh!=NULL) {
          if (thisTh->status==RUN)
            nFatalError("schedule", "Thread should be READY\n");
          if ( thisTh->status==READY &&
               !nth_queryThread(nth_fcfsReadyQueue, thisTh) )
            nFatalError("schedule", "Ready thread not in ready queue\n");
        }
      );
      nth_changeContext(thisTh, nextTh);
      // Some time later, at return the scheduler gave back onother core
      // to thisTh, but most probably coreId() != prevCoreId
      if (thisTh->status==READY)
        break;
    }

    nth_corePark();
  } 
  DBG(
    if (thisTh!=nSelf())
      nFatalError("nth_fcfsSchedule", "nSelf() inconsistency\n");
  );
  CHECK_STACK
  thisTh->status= RUN;
  if (!nth_emptyQueue(nth_fcfsReadyQueue))
    nth_reviewCores();
}

static void nth_fcfsStop(void) {
  CHECK_CRITICAL("nth_fcfsStop")

  nth_destroyQueue(nth_fcfsReadyQueue);
}

static Scheduler nth_fcfsScheduler= { .schedule = nth_fcfsSchedule,
                               .setReady = nth_fcfsSetReady,
                               .suspend = nth_fcfsSuspend,
                               .stop = nth_fcfsStop };
void setFcfsScheduling() {
  START_CRITICAL

  if (nth_verbose)
    printf( "Info: setting %d-core FCFS scheduling\n", nth_totalCores);

  nth_fcfsReadyQueue= nth_makeQueue();
  nth_setScheduler(nth_fcfsScheduler);
  MapIterator *iter= getMapIterator(nth_threadSet);
  void *ptr;
  while (mapNext(iter, &ptr, &ptr)) {
    nThread th= ptr;
    if (th->status==READY)
      nth_putBack(nth_fcfsReadyQueue, th);
  }
  destroyMapIterator(iter);

  END_CRITICAL
}

void allocThreadFcfs(nThread th, int coreId) {
  START_CRITICAL

  if (! (0<=coreId && coreId<nth_totalCores))
    printf("The core %d does not exist\n", coreId);
  int id= nth_allocCoreId(th);
  if (id>=0)
    printf("The thread is already allocated at core %d\n", id);
  if (!nth_coreIsIdle[coreId])
    printf("Core %d is not idle\n", coreId);
  if (nth_queryThread(nth_fcfsReadyQueue, th))
    nth_delQueue(nth_fcfsReadyQueue, th);
  nth_putFront(nth_fcfsReadyQueue, th);
  nth_coreWakeUp(coreId);
  END_CRITICAL
}

int isFcfsScheduling(void) {
  return nth_scheduler.schedule==nth_fcfsScheduler.schedule;
}

#define _GNU_SOURCE 1

#include "nthread-impl.h"
#include <sys/resource.h>

static void nth_setCoreTimerAlarm(long long sliceNanos, int coreId);
static long long nth_getCoreNanos();

long long nth_sliceNanos= 0; // Duration of the time slice before preempting
static timer_t *nth_timerSet;

static __thread clockid_t nth_clockid;

static NthQueue *nth_rrReadyQueue;

static void nth_VTimerHandler(int sig, siginfo_t *si, void *uc);


void nth_rrInit(void) {
  nth_timerSet= malloc(nth_totalCores*sizeof(*nth_timerSet));
}

void nth_rrThreadInit(void) {
  if (pthread_getcpuclockid(pthread_self(), &nth_clockid)!=0) {
    perror("pthread_getcpuclockid");
    nFatalError("nth_rrThreadInit", "Cannot continue\n");
  }

  struct sigaction sigact;
  sigact.sa_flags= SA_SIGINFO;
  sigact.sa_sigaction= nth_VTimerHandler;
  sigact.sa_mask= nth_sigsetCritical;

  if (sigaction(SIGVTALRM, &sigact, NULL)!=0) {
    perror("sigaction");
    nFatalError("nth_rrThreadInit", "Cannot continue\n");
  }

  struct sigevent sigev;
  sigev.sigev_notify= SIGEV_THREAD_ID;
  sigev._sigev_un._tid= gettid();
  sigev.sigev_signo= SIGVTALRM;
  sigev.sigev_value.sival_ptr= &nth_timerSet[nth_coreId()];
  if ( timer_create(CLOCK_THREAD_CPUTIME_ID,
                    &sigev, &nth_timerSet[nth_coreId()])!=0 ) {
    perror("timer_create");
    nFatalError("nth_rrThreadInit", "Cannot continue\n");
  }
}

static long long nth_getCoreNanos() {
  struct timespec ts;
  if (clock_gettime(nth_clockid, &ts)!=0) {
    perror("clock_gettime");
    nFatalError("nth_getCoreNanos", "Cannot continue\n");
  }
  return (long long)ts.tv_sec*1000000000+ts.tv_nsec;
}

static void nth_VTimerHandler(int sig, siginfo_t *si, void *uc) {
  nThread th= nth_selfCritical();
  if (th==NULL)
    return; // It has been called for nth_coreFun()

  START_HANDLER
# ifdef TRACESCHED
    printk("SCHED %d:SIGVTALRM\n", nth_coreId());
# endif  

  th->sliceNanos= 0;
  if (!nth_emptyQueue(nth_rrReadyQueue))
    nth_implicitContextChanges++;

  // If this core is waiting in sigsuspend in nth_rrSchedule,
  // do not call recursively nth_rrSchedule

  if ( !nth_coreIsIdle[nth_coreId()] ) {
    schedule();
  }

  END_HANDLER
}

static void nth_rrSetReady(nThread th) {
  CHECK_CRITICAL("nth_rrSetReady")

  assert(th->status!=READY && th->status!=RUN && th->timequeue==NULL);

  int prevStatus= th->status;
  (void)prevStatus;

  th->status= READY;
  if (nth_allocCoreId(th)<0) {
    if (th->sliceNanos>0) {               // it has some slice yet
      nth_putFront(nth_rrReadyQueue, th);
    }
    else {                                // it exhausted its slice
      th->sliceNanos= nth_sliceNanos;     // give it a whole new slice and
      nth_putBack(nth_rrReadyQueue, th);  // put it at the end of the queue
    }
#   ifdef TRACESCHED
      printk( "SCHED %d:setReady %s %s %d us\n", nth_coreId(),
              th->name, nth_stateNames[prevStatus], th->sliceNanos/1000 );
#   endif
  }
  else if (nth_allocCoreId(th)!=nth_coreId()) {
    // Thread th is allocated to nth_allocCoreId(th), wake it up
#   ifdef TRACESCHED
      printk( "SCHED %d:setReady %s %s %d us alloc at %d\n", nth_coreId(),
               th->name, nth_stateNames[prevStatus], th->sliceNanos/1000,
               nth_allocCoreId(th) );
#   endif
    // Not needed: nth_delQueue(nth_rrReadyQueue, th);
    nth_coreWakeUp(nth_allocCoreId(th));
  }
# ifdef TRACESCHED
  else {
    printk("SCHED %d:setReady %s same core\n", nth_coreId(), th->name);
  }
# endif
}

static void nth_rrSuspend(State waitState) {
  CHECK_CRITICAL("nth_rrSuspend")

  nThread th= nSelf();
# ifdef TRACESCHED
    printk( "SCHED %d:suspend(%s,%s)\n",
            nth_coreId(), th->name, nth_stateNames[th->status] );
# endif
  // if (th->status==READY)
  //   nth_delQueue(nth_rrReadyQueue, th);
  assert(th->status==RUN);

  th->status= waitState;
}

static void nth_rrSchedule(void) {
  CHECK_CRITICAL("nth_rrSchedule")

  // int prevCoreId= coreId();

  nThread thisTh= nSelf();

  if (thisTh!=NULL) {
    long long endNanos= nth_getCoreNanos();
    thisTh->sliceNanos -= endNanos-thisTh->startCoreNanos;
  }
  // thisTh->sliceNanos can be negative if the slice expired when
  // signals were disabled

  for (;;) {
    if (thisTh!=NULL && (thisTh->status==READY || thisTh->status==RUN)) {
      if (nth_queryThread(nth_rrReadyQueue, thisTh))
        nFatalError("nth_rrSchedule", "Thread should not be in ready queue\n");
      if (thisTh->sliceNanos>0) {
#       ifdef TRACESCHED
          printk( "SCHED %d:sched %s %s %d us\n", nth_coreId(),
                  thisTh->name, nth_stateNames[thisTh->status],
                  thisTh->sliceNanos/1000 );
#       endif
        break; // Continue running same allocated thread
      }
      else {
        thisTh->sliceNanos= nth_sliceNanos;
        if (nth_emptyQueue(nth_rrReadyQueue)) {
#         ifdef TRACESCHED
            printk( "SCHED %d:sched %s %s %d us\n", nth_coreId(),
                    thisTh->name, nth_stateNames[thisTh->status],
                    thisTh->sliceNanos/1000 );
#         endif
          break;
        }
#       ifdef TRACESCHED
          printk( "SCHED %d:sched %s %s %d us\n", nth_coreId(),
                  thisTh->name, nth_stateNames[thisTh->status],
                  thisTh->sliceNanos/1000 );
#       endif
        thisTh->status= READY;
        nth_putBack(nth_rrReadyQueue, thisTh);
      }
    }

    nThread nextTh= nth_getFront(nth_rrReadyQueue);
    if (nextTh!=NULL) {
      if (nth_allocCoreId(nextTh) != -1)
        nFatalError("nth_rrSchedule", "Thread should not be in ready queue\n");

      // The context change: give this core to nextTh
      // it will take a while to return from here
      // Meanwhile thread nextTh and others are being executed

#     ifdef TRACESCHED
        printk( "SCHED %d:switch %s %s %d us -> %s %s %d us\n", nth_coreId(),
                thisTh!=NULL ? thisTh->name : NULL,
                thisTh!=NULL ? nth_stateNames[thisTh->status] : NULL,
                thisTh!=NULL ? thisTh->sliceNanos/1000 : 0,
                nextTh->name, nth_stateNames[nextTh->status],
                nextTh->sliceNanos/1000 );
#     endif

      assert( thisTh==NULL || thisTh->status!=READY ||
              nth_queryThread(nth_rrReadyQueue, thisTh) );
      nth_changeContext(thisTh, nextTh);

      // Some time later, at return the scheduler gave back onother core
      // to thisTh so probably previous core != next core
      if (thisTh->status==READY)
        break;
    }

    if (thisTh!=nSelf())
      nFatalError("nth_rrSchedule", "nSelf() inconsistency\n");

    // No threads to execute: the core will be parked

    nth_corePark();
  }

  if (thisTh!=nSelf())
    nFatalError("nth_rrSchedule", "nSelf() inconsistency\n");

  CHECK_STACK
  if (thisTh->status!=READY && thisTh->status!=RUN)
    nFatalError("nth_rrSchedule", "Thread is not ready to run\n");
  thisTh->status= RUN;
  thisTh->startCoreNanos= nth_getCoreNanos();

  if (!nth_emptyQueue(nth_rrReadyQueue))
    nth_reviewCores();
  nth_setCoreTimerAlarm(thisTh->sliceNanos, nth_coreId());
}

static void nth_setCoreTimerAlarm(long long sliceNanos, int coreId) {
  struct itimerspec slicespec;
  slicespec.it_value.tv_sec= sliceNanos/1000000000;
  slicespec.it_value.tv_nsec= sliceNanos%1000000000;
  slicespec.it_interval.tv_sec= 0;
  slicespec.it_interval.tv_nsec= 0;
  int rc= timer_settime(nth_timerSet[coreId], 0, &slicespec, NULL);
  if (rc!=0) {
    if (rc==-1)
      perror("timer_settime");
    nFatalError("timer_settime", "Failed to set time alarm, cannot continue\n");
  }
}

static void nth_rrStop(void) {
  CHECK_CRITICAL("nth_rrStop")

  // Disarm all timers
  int ncores= nth_totalCores;
  for (int i= 0; i<ncores; i++) {
    nth_setCoreTimerAlarm(0, i);
  }

  nth_destroyQueue(nth_rrReadyQueue);
}

Scheduler nth_rrScheduler= { .schedule = nth_rrSchedule,
                               .setReady = nth_rrSetReady,
                               .suspend = nth_rrSuspend,
                               .stop = nth_rrStop };

void nSetTimeSlice(long long sliceNanos) {
  START_CRITICAL

  if (nth_verbose)
    printf("Info: setting %d-core round robin scheduling\n", nth_totalCores);

  nth_sliceNanos= sliceNanos;

  if (!isRRScheduling()) {
    nth_rrReadyQueue= nth_makeQueue();
    nth_setScheduler(nth_rrScheduler);
    MapIterator *iter= getMapIterator(nth_threadSet);
    void *ptr;
    while (mapNext(iter, &ptr, &ptr)) {
      nThread th= ptr;
      if (th->status==READY) {
        th->sliceNanos= sliceNanos;
        nth_putBack(nth_rrReadyQueue, th);
      }
      else if (th->status==RUN) {
        int coreId= th->allocCoreId;
        th->sliceNanos= sliceNanos;
        // Arm timer for thread th
        nth_setCoreTimerAlarm(sliceNanos, coreId);
      }
    }
    destroyMapIterator(iter);
  }
  else {
    MapIterator *iter= getMapIterator(nth_threadSet);
    void *ptr;
    while (mapNext(iter, &ptr, &ptr)) {
      nThread th= ptr;
      if (th->status==READY) {
        th->sliceNanos= nth_sliceNanos;
      }
      else if (th->status==RUN) {
        int coreId= th->allocCoreId;
        // Arm timer for thread th
        nth_setCoreTimerAlarm(sliceNanos, coreId);
      }
    }
    destroyMapIterator(iter);
  }

  END_CRITICAL
}

void allocThreadRR(nThread th, int coreId) {
  START_CRITICAL

  if (! (0<=coreId && coreId<nth_totalCores))
    printf("The core %d does not exist\n", coreId);
  int id= nth_allocCoreId(th);
  if (id>=0)
    printf("The thread is already allocated at core %d\n", id);
  if (!nth_coreIsIdle[coreId])
    printf("Core %d is not idle\n", coreId);
  if (nth_queryThread(nth_rrReadyQueue, th))
    nth_delQueue(nth_rrReadyQueue, th);
  nth_putFront(nth_rrReadyQueue, th);
  nth_coreWakeUp(coreId);
  END_CRITICAL
}

int isRRScheduling(void) {
  return nth_scheduler.schedule==nth_rrScheduler.schedule;
}

#define _XOPEN_SOURCE 500

#include "nthread-impl.h"

static NthQueue *nth_pri1ReadyQueue[MAXPRI];

void nSetPriority(nThread th, int pri) {
  START_CRITICAL

  th->pri= pri;
  schedule(); // The calling thread may loose the CPU if its priority is lower

  END_CRITICAL
}

static void nth_pri1SetReady(nThread th) {
  CHECK_CRITICAL("nth_fcfsSetReady")

  if (th->status==READY || th->status==RUN)
    nFatalError("nth_fcfsReady", "The thread was already in READY status\n");

  th->status= READY;
  nth_putBack(nth_pri1ReadyQueue[th->pri], th);
}

static void nth_pri1Suspend(State waitState) {
  CHECK_CRITICAL("nth_fcfsSuspend")

  nThread th= nSelf();
  if (th->status!=RUN && th->status!=READY)
    nFatalError("nth_fcfsSuspend", "Thread was not ready or run\n");
  th->status= waitState;
}

static void nth_pri1Schedule(void) {
  CHECK_CRITICAL("nth_fcfsSchedule")

  // int prevCoreId= coreId();
  nThread thisTh= nSelf();
  if (thisTh!=NULL && (thisTh->status==READY || thisTh->status==RUN)) {
    thisTh->status= READY;
    nth_putBack(nth_pri1ReadyQueue[thisTh->pri], thisTh);
  }

  nThread nextTh= NULL;
  while (nextTh==NULL) {
    int i=0;
    while (i<MAXPRI) {
      if (!nth_emptyQueue(nth_pri1ReadyQueue[i]))
        break;
      i++;
    }
    if (i<MAXPRI) {
      nextTh= nth_getFront(nth_pri1ReadyQueue[i]);
      break;
    }
    else {
      nth_corePark();
    }
  }

  // The context change: give this core to nextTh
  // it will take a while to return from here
  // Meanwhile thread nextTh and others are being executed

  nth_changeContext(thisTh, nextTh);

  // Some time later, at return the scheduler gave back onother core
  // to thisTh, but most probably coreId() != prevCoreId

  thisTh->status= RUN;
}

static void nth_pri1Stop(void) {
  CHECK_CRITICAL("nth_fcfsStop")

  for (int i= 0; i<MAXPRI; i++)
    nth_destroyQueue(nth_pri1ReadyQueue[i]);
}

Scheduler nth_pri1Scheduler= { .schedule = nth_pri1Schedule,
                               .setReady = nth_pri1SetReady,
                               .suspend = nth_pri1Suspend,
                               .stop = nth_pri1Stop };
void setPri1Scheduling() {
  START_CRITICAL

  if (nth_verbose)
    printf("Info: setting single-core priority scheduling\n");

  if (nth_totalCores!=1)
    nFatalError("setPri1Scheduling",
                "This priority scheduler only accepts a single core\n");
  for (int i= 0; i<MAXPRI; i++)
    nth_pri1ReadyQueue[i]= nth_makeQueue();
  nth_setScheduler(nth_pri1Scheduler);
  MapIterator *iter= getMapIterator(nth_threadSet);
  void *ptr;
  while (mapNext(iter, &ptr, &ptr)) {
    nThread th= ptr;
    if (th->status==READY)
      nth_putBack(nth_pri1ReadyQueue[th->pri], th);
  }
  destroyMapIterator(iter);

  END_CRITICAL
}

int isPri1Scheduling(void) {
  return nth_scheduler.schedule==nth_pri1Scheduler.schedule;
}

