```c
#include <nthread-impl.h>
#include "subasta.h"

typedef struct oferta {
  struct oferta *prev, *next;
  nThread th;
  double monto;
  int resultado;
} Oferta;

struct subasta {
  int n;
  int cerradas;
  Oferta *head, *tail;
  int count;
};

static void insertSorted(nSubasta s, Oferta *of) {
  Oferta *cur = s->head;
  // Find first position where cur->monto <= of->monto
  while (cur != NULL && cur->monto > of->monto) {
    cur = cur->next;
  }
  if (cur == NULL) {
    // Insert at end
    of->prev = s->tail;
    of->next = NULL;
    if (s->tail != NULL) s->tail->next = of;
    else s->head = of;
    s->tail = of;
  } else {
    // Insert before cur
    of->next = cur;
    of->prev = cur->prev;
    if (cur->prev != NULL) cur->prev->next = of;
    else s->head = of;
    cur->prev = of;
  }
}

static void removeFromList(nSubasta s, Oferta *of) {
  if (of->prev != NULL) of->prev->next = of->next;
  else s->head = of->next;
  if (of->next != NULL) of->next->prev = of->prev;
  else s->tail = of->prev;
  of->prev = of->next = NULL;
}

nSubasta nNuevaSubasta(int n) {
  nSubasta s = nMalloc(sizeof(struct subasta));
  s->n = n;
  s->cerradas = 0;
  s->head = s->tail = NULL;
  s->count = 0;
  return s;
}

int nOfrecer(nSubasta s, double precio) {
  START_CRITICAL

  if (s->cerradas) {
    END_CRITICAL
    return FALSE;
  }

  Oferta *of = nMalloc(sizeof(Oferta));
  of->th = nSelf();
  of->monto = precio;
  of->resultado = 0;
  of->prev = of->next = NULL;

  if (s->count < s->n) {
    insertSorted(s, of);
    s->count++;
    suspend(WAIT_SUBASTA);
    schedule();
    int rc = of->resultado;
    nFree(of);
    END_CRITICAL
    return rc;
  }

  // count == n, check worst
  if (precio > s->tail->monto) {
    Oferta *worst = s->tail;
    removeFromList(s, worst);
    s->count--;
    worst->resultado = FALSE;
    setReady(worst->th);
    schedule();

    insertSorted(s, of);
    s->count++;
    suspend(WAIT_SUBASTA);
    schedule();
    int rc = of->resultado;
    nFree(of);
    END_CRITICAL
    return rc;
  }

  // Loses immediately
  nFree(of);
  END_CRITICAL
  return FALSE;
}

double nAdjudicar(nSubasta s, int *punid) {
  START_CRITICAL

  s->cerradas = 1;
  double total = 0;
  int count = 0;
  Oferta *of = s->head;
  while (of != NULL) {
    total += of->monto;
    count++;
    of->resultado = TRUE;
    setReady(of->th);
    of = of->next;
  }
  *punid = s->n - count;
  schedule();

  END_CRITICAL
  return total;
}

void nDestruirSubasta(nSubasta s) {
  START_CRITICAL
  // Free any remaining oferta structures
  Oferta *of = s->head;
  while (of != NULL) {
    Oferta *next = of->next;
    nFree(of);
    of = next;
  }
  nFree(s);
  END_CRITICAL
}
```

