typedef struct oferta {
  struct oferta *prev;
  struct oferta *next;
  nThread th;
  double monto;
  int resultado;
} Oferta;

struct subasta {
  int n;            // Cantidad de items
  int cerradas;     // 1 si ya se adjudico
  Oferta *head;     // Inicio de la lista ordenada (mayor a menor)
  Oferta *tail;     // Final de la lista (peor oferta)
  int count;        // Cantidad de ofertas en la lista
};

// Inserta of en la lista ordenada por monto descendente
static void insertSorted(nSubasta s, Oferta *of) {
  Oferta *cur = s->head;
  // Encontrar primer cur con cur->monto <= of->monto
  while (cur != NULL && cur->monto > of->monto) {
    cur = cur->next;
  }
  if (cur == NULL) {
    of->prev = s->tail;
    of->next = NULL;
    if (s->tail != NULL) s->tail->next = of;
    else s->head = of;
    s->tail = of;
  } else {
    of->next = cur;
    of->prev = cur->prev;
    if (cur->prev != NULL) cur->prev->next = of;
    else s->head = of;
    cur->prev = of;
  }
}

static void removeFromList(nSubasta s, Oferta *of) {
  if (of->prev != NULL) of->prev->next = of->next;
  else s->head = of->next;
  if (of->next != NULL) of->next->prev = of->prev;
  else s->tail = of->prev;
  of->prev = NULL;
  of->next = NULL;
}

nSubasta nNuevaSubasta(int n) {
  nSubasta s = nMalloc(sizeof(struct subasta));
  s->n = n;
  s->cerradas = 0;
  s->head = NULL;
  s->tail = NULL;
  s->count = 0;
  return s;
}

int nOfrecer(nSubasta s, double precio) {
  START_CRITICAL

  if (s->cerradas) {
    END_CRITICAL
    return FALSE;
  }

  int accept = 0;
  if (s->count < s->n) {
    accept = 1;
  } else if (s->count > 0 && precio > s->tail->monto) {
    accept = 1;
  }

  if (!accept) {
    END_CRITICAL
    return FALSE;
  }

  Oferta *of = nMalloc(sizeof(Oferta));
  of->th = nSelf();
  of->monto = precio;
  of->resultado = 0;
  of->prev = NULL;
  of->next = NULL;

  if (s->count == s->n) {
    // Desplazar a la peor oferta
    Oferta *worst = s->tail;
    removeFromList(s, worst);
    s->count--;
    worst->resultado = FALSE;
    setReady(worst->th);
  }

  insertSorted(s, of);
  s->count++;
  suspend(WAIT_SUBASTA);
  schedule();
  int rc = of->resultado;
  nFree(of);
  END_CRITICAL
  return rc;
}

double nAdjudicar(nSubasta s, int *punid) {
  START_CRITICAL

  s->cerradas = 1;
  double total = 0;
  int count = 0;
  Oferta *of = s->head;
  while (of != NULL) {
    Oferta *next = of->next;
    total += of->monto;
    count++;
    of->resultado = TRUE;
    setReady(of->th);
    of = next;
  }
  *punid = s->n - count;
  schedule();

  END_CRITICAL
  return total;
}

void nDestruirSubasta(nSubasta s) {
  START_CRITICAL
  // Por si quedan oferentes esperando
  Oferta *of = s->head;
  while (of != NULL) {
    Oferta *next = of->next;
    if (of->resultado == 0) {
      of->resultado = FALSE;
      setReady(of->th);
    }
    of = next;
  }
  schedule();
  nFree(s);
  END_CRITICAL
}
