#include <nthread-impl.h>
#include "subasta.h"

// =============================================================
// Implemente a partir de aca el tipo Subasta, puede agregar
// funciones, estructuras o variables que considere necesarias
// =============================================================

// Cada oferta registrada en la subasta.
// La lista se mantiene ordenada por monto descendente para poder
// identificar rapidamente a la peor oferta actual (la cola de la lista).
typedef struct oferta {
  struct oferta *prev;
  struct oferta *next;
  nThread th;          // thread que realizo la oferta
  double monto;        // monto ofrecido
  int resultado;       // TRUE / FALSE / 0 mientras espera
} Oferta;

struct subasta {
  int n;               // cantidad de items subastados
  int cerradas;        // 1 si ya se adjudico (nAdjudicar)
  Oferta *head;        // mejor oferta (mayor monto)
  Oferta *tail;        // peor oferta (menor monto)
  int count;           // cantidad de ofertas en la lista
};

// Inserta la oferta of en la lista ordenada por monto descendente.
// Las ofertas con el mismo monto quedan en orden FIFO.
static void insertSorted(nSubasta s, Oferta *of) {
  Oferta *cur = s->head;
  while (cur != NULL && cur->monto > of->monto) {
    cur = cur->next;
  }
  if (cur == NULL) {
    // insertar al final
    of->prev = s->tail;
    of->next = NULL;
    if (s->tail != NULL)
      s->tail->next = of;
    else
      s->head = of;
    s->tail = of;
  } else {
    // insertar antes de cur
    of->next = cur;
    of->prev = cur->prev;
    if (cur->prev != NULL)
      cur->prev->next = of;
    else
      s->head = of;
    cur->prev = of;
  }
}

// Remueve of de la lista doblemente enlazada
static void removeFromList(nSubasta s, Oferta *of) {
  if (of->prev != NULL)
    of->prev->next = of->next;
  else
    s->head = of->next;
  if (of->next != NULL)
    of->next->prev = of->prev;
  else
    s->tail = of->prev;
  of->prev = NULL;
  of->next = NULL;
}

nSubasta nNuevaSubasta(int n) {
  nSubasta s = nMalloc(sizeof(struct subasta));
  s->n = n;
  s->cerradas = 0;
  s->head = NULL;
  s->tail = NULL;
  s->count = 0;
  return s;
}

int nOfrecer(nSubasta s, double precio) {
  START_CRITICAL

  if (s->cerradas) {
    END_CRITICAL
    return FALSE;
  }

  // Determinar si la oferta puede ser aceptada.
  // Se acepta cuando:
  //   - hay espacio en la lista (count < n), o
  //   - el precio supera al peor actual (precio > tail->monto)
  int accept = 0;
  if (s->count < s->n) {
    accept = 1;
  } else if (s->count > 0 && precio > s->tail->monto) {
    accept = 1;
  }

  if (!accept) {
    END_CRITICAL
    return FALSE;
  }

  Oferta *of = nMalloc(sizeof(Oferta));
  of->th = nSelf();
  of->monto = precio;
  of->resultado = 0;
  of->prev = NULL;
  of->next = NULL;

  // Si la lista esta llena, desplazar a la peor oferta
  if (s->count == s->n) {
    Oferta *worst = s->tail;
    removeFromList(s, worst);
    s->count--;
    worst->resultado = FALSE;
    setReady(worst->th);
  }

  insertSorted(s, of);
  s->count++;

  // Esperar hasta que la subasta cierre o esta oferta sea desplazada
  suspend(WAIT_SUBASTA);
  schedule();

  int rc = of->resultado;
  // Si fuimos adjudicados, retiramos nuestra entrada de la lista
  // para no dejar punteros colgantes cuando se libere `of`.
  if (rc == TRUE) {
    removeFromList(s, of);
    s->count--;
  }
  nFree(of);

  END_CRITICAL
  return rc;
}

double nAdjudicar(nSubasta s, int *punid) {
  START_CRITICAL

  s->cerradas = 1;

  double total = 0;
  int count = 0;
  Oferta *of = s->head;
  while (of != NULL) {
    Oferta *next = of->next;
    total += of->monto;
    count++;
    of->resultado = TRUE;
    setReady(of->th);
    of = next;
  }
  if (punid != NULL)
    *punid = s->n - count;

  schedule();

  END_CRITICAL
  return total;
}

void nDestruirSubasta(nSubasta s) {
  START_CRITICAL

  // Si quedan oferentes suspendidos, los despertamos como perdedores.
  int had_pending = 0;
  Oferta *of = s->head;
  while (of != NULL) {
    Oferta *next = of->next;
    if (of->resultado == 0) {
      of->resultado = FALSE;
      setReady(of->th);
      had_pending = 1;
    }
    of = next;
  }
  if (had_pending)
    schedule();

  // Cada thread libera su propio Oferta al despertarse.
  // Aqui solo liberamos la estructura de la subasta.
  nFree(s);

  END_CRITICAL
}

